where session_id = '11111111-1111-1111-1111-111111111111';

delete from public.game_players
where session_id = '11111111-1111-1111-1111-111111111111';

delete from public.game_sessions
where id = '11111111-1111-1111-1111-111111111111'
   or session_code = 'QRT001';

insert into public.game_sessions (
  id,
  session_code,
  status,
  host_player_id,
  deck_id,
  winner_player_id,
  state,
  version,
  created_at,
  updated_at
)
values (
  '11111111-1111-1111-1111-111111111111',
  'QRT001',
  'running',
  'p1',
  'military-jets-v1',
  null,
  '{}'::jsonb,
  1,
  now(),
  now()
);

insert into public.game_players (id, session_id, player_name, color, is_host, seat_index)
values
  ('p1', '11111111-1111-1111-1111-111111111111', 'You', '#01ADFF', true, 1),
  ('p2', '11111111-1111-1111-1111-111111111111', 'Opponent', '#C669FF', false, 2);

update public.game_sessions
set state = jsonb_build_object(
  'sessionId', '11111111-1111-1111-1111-111111111111',
  'sessionCode', 'QRT001',
  'status', 'running',
  'hostPlayerId', 'p1',
  'deckId', 'military-jets-v1',
  'winnerPlayerId', null,
  'players', jsonb_build_array(
    jsonb_build_object(
      'id', 'p1',
      'name', 'You',
      'color', '#01ADFF',
      'hand', (
        select jsonb_agg(
          jsonb_build_object(
            'id', c.id,
            'code', c.code,
            'category', c.category,
            'imageUrl', c.image_url,
            'specs', c.specs
          )
          order by c.sort_order
        )
        from public.deck_cards c
        where c.deck_id = 'military-jets-v1'
          and c.sort_order in (1, 3, 5, 7, 9, 11, 13, 15)
      )
    ),
    jsonb_build_object(
      'id', 'p2',
      'name', 'Opponent',
      'color', '#C669FF',
      'hand', (
        select jsonb_agg(
          jsonb_build_object(
            'id', c.id,
            'code', c.code,
            'category', c.category,
            'imageUrl', c.image_url,
            'specs', c.specs
          )
          order by c.sort_order
        )
        from public.deck_cards c
        where c.deck_id = 'military-jets-v1'
          and c.sort_order in (2, 4, 6, 8, 10, 12, 14, 16)
      )
    )
  ),
  'selectedSpecKey', null,
  'selectedByPlayerId', null,
  'pendingTransfer', null,
  'loseTieRequest', null,
  'tieState', jsonb_build_object(
    'active', false,
    'rounds', 0,
    'potCards', '[]'::jsonb,
    'pendingLoseTieRequestId', null
  ),
  'version', 1,
  'updatedAt', now()::text
)
where id = '11111111-1111-1111-1111-111111111111';

